final class WssTimestampValidator {
    private final Clock clock;
    private final Duration allowedClockSkew;
    private final Duration replayCacheTtl;
    private final ReplayCache replayCache = new ReplayCache();

    WssTimestampValidator(Clock clock, Duration allowedClockSkew, Duration replayCacheTtl) {
        this.clock = Objects.requireNonNull(clock);
        this.allowedClockSkew = Objects.requireNonNull(allowedClockSkew);
        this.replayCacheTtl = Objects.requireNonNull(replayCacheTtl);
    }

    void validateOrThrow(WssTimestamp ts) {
        if (ts == null) throw SoapFaults.client("Missing WS-Security Timestamp.");
        if (ts.created == null || ts.expires == null) throw SoapFaults.client("Incomplete WS-Security Timestamp.");
        if (!ts.expires.isAfter(ts.created)) throw SoapFaults.client("Invalid Timestamp: Expires must be after Created.");

        Instant now = Instant.now(clock);

        Instant createdMin = now.minus(allowedClockSkew);
        Instant expiresMax = now.plus(allowedClockSkew);

        if (ts.created.isAfter(expiresMax)) {
            throw SoapFaults.client("Timestamp Created is in the future beyond allowed clock skew.");
        }
        if (ts.expires.isBefore(createdMin)) {
            throw SoapFaults.client("Timestamp is expired.");
        }

        String replayKey = ts.id + "|" + ts.created.toString() + "|" + ts.expires.toString();
        boolean firstSeen = replayCache.putIfAbsent(replayKey, now.plus(replayCacheTtl));
        if (!firstSeen) {
            throw SoapFaults.client("Replay detected (duplicate WS-Security Timestamp).");
        }
        replayCache.purgeExpired(now);
    }

    static final class ReplayCache {
        private final ConcurrentMap<String, Instant> exp = new ConcurrentHashMap<>();

        boolean putIfAbsent(String key, Instant expiresAt) {
            Instant prev = exp.putIfAbsent(key, expiresAt);
            return prev == null;
        }

        void purgeExpired(Instant now) {
            for (var e : exp.entrySet()) {
                Instant t = e.getValue();
                if (t != null && !t.isAfter(now)) exp.remove(e.getKey(), t);
            }
        }
    }
}

